    headers: { 'Accept': 'application/json' }
  });
  const data = await response.json();
  const sorted = data.sort((a, b) => b.total - a.total);
  return sorted.slice(0, 30).map((item, index) => ({
    rank: index + 1,
    login: item.author.login,
    total: item.total
  }));
}

